const projects = $input.first().json || [];
const alerts = [];
for (const p of projects) {
  const budgetVar = p.budget > 0 ? ((p.actual_cost - p.budget) / p.budget) : 0;
  const today = new Date();
  const target = new Date(p.target_completion);
  const daysRemaining = Math.ceil((target - today) / 86400000);
  const completion = p.completion_percent || 0;
  const isDelayed = daysRemaining < 0;
  const overBudget = budgetVar > 0.10;
  if (isDelayed || overBudget) {
    alerts.push({ project_id: p.project_id, status: p.status, budget_variance: (budgetVar * 100).toFixed(1) + '%', days_remaining: daysRemaining, completion_pct: completion, over_budget: overBudget, delayed: isDelayed });
  }
}
return alerts.length ? alerts.map(a => ({ json: a })) : [{ json: { no_alerts: true } }];

